    def test_positive_inputs(self):
        self.assertEqual(B10(1), 10)
        self.assertEqual(B10(42), 10)
        self.assertEqual(B10(999), 10)

    def test_negative_inputs(self):
        self.assertEqual(B10(-1), 10)
        self.assertEqual(B10(-100), 10)

    def test_zero_input(self):
